import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import "./AuthPage.css";

const AuthPage = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({
    libraryId: "",
    email: "",
    password: "",
    name: "",
    userType: "Student",
  });
  const [showModal, setShowModal] = useState(false);
  const [generatedLibraryId, setGeneratedLibraryId] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const generateLibraryId = () => {
    return `LIB${Math.floor(100000 + Math.random() * 900000)}`;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (isLogin) {
      if (!formData.libraryId || !formData.email || !formData.password) {
        toast.error("All fields are required.", { position: "top-center", autoClose: 3000 });
        return;
      }
      toast.success("Login Successful ✅", { position: "top-center", autoClose: 3000 });
      setTimeout(() => navigate("/dashboard"), 2000);
    } else {
      const newLibraryId = generateLibraryId();
      setGeneratedLibraryId(newLibraryId);
      setShowModal(true);
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    navigate("/");
  };

  return (
    <div className="auth-container">
      <div className="auth-box">
  <h2>{isLogin ? "📚 Library Portal" : "📖 Join the Library"}</h2>
  <form onSubmit={handleSubmit}>
    {!isLogin && (
      <>
        <input type="text" name="name" placeholder="Full Name" value={formData.name} onChange={handleChange} required />
        <select name="userType" value={formData.userType} onChange={handleChange} required>
          <option value="Student">Student</option>
          <option value="Faculty">Faculty</option>
          <option value="Librarian">Librarian (Admin)</option>
        </select>
      </>
    )}
    {isLogin && <input type="text" name="libraryId" placeholder="Library ID" value={formData.libraryId} onChange={handleChange} required />}
    <input type="email" name="email" placeholder="Email" value={formData.email} onChange={handleChange} required />
    <input type="password" name="password" placeholder="Password" value={formData.password} onChange={handleChange} required />
    <button type="submit">{isLogin ? "Login" : "Sign Up"}</button>
  </form>

  <p>{isLogin ? <>New to the library? <span onClick={() => setIsLogin(false)}>Sign up</span></> : <>Already a member? <span onClick={() => setIsLogin(true)}>Login</span></>}</p>

  {/* Place the modal inside auth-box */}
  {showModal && (
    <div className="modal-overlay">
      <div className="modal">
        <h3>Signup Successful ✅</h3>
        <p>Your Library ID: <strong>{generatedLibraryId}</strong></p>
        <button onClick={handleCloseModal}>OK</button>
      </div>
    </div>
  )}
</div>
    </div>
  );
};

export default AuthPage;
